-- ═══════════════════════════════════════════════════════════════
-- KARAENGTA HRIS — Import Data Lengkap
-- Dibuat dari: DASHBOARD_HR.xlsx + Lamaran_Kerja___Jawaban_.xlsx
--
-- CARA IMPORT KE SUPABASE:
-- 1. Buka https://supabase.com → masuk ke project kamu
-- 2. Klik "SQL Editor" di sidebar kiri
-- 3. Klik "+ New query"
-- 4. Copy-paste SECTION 1 dulu → klik "Run"
-- 5. Lanjut copy-paste SECTION 2, 3, 4 satu per satu
--    (pisah per section karena file ini besar)
-- 6. Pastikan tidak ada error merah sebelum lanjut ke section berikutnya
--
-- PENTING: Jalankan Section 1 (karyawan) TERLEBIH DAHULU
-- sebelum section lain karena absensi/SP/rekrutmen butuh employee_id yang valid
-- ═══════════════════════════════════════════════════════════════

-- ═══ SECTION 1: KARYAWAN (122 orang unik) ═══
ON CONFLICT (employee_id) DO UPDATE SET
  name = EXCLUDED.name, status = EXCLUDED.status,
  position = EXCLUDED.position, employment_status = EXCLUDED.employment_status,
  end_date = EXCLUDED.end_date;


-- ═══ SECTION 2: ABSENSI BULANAN (445 records) ═══
ON CONFLICT (employee_id, bulan) DO UPDATE SET
  total_hadir=EXCLUDED.total_hadir, terlambat=EXCLUDED.terlambat,
  cuti=EXCLUDED.cuti, sakit=EXCLUDED.sakit, izin=EXCLUDED.izin, alpha=EXCLUDED.alpha;


-- ═══ SECTION 3: SURAT PERINGATAN (16 records) ═══
;


-- ═══ SECTION 4: REKRUTMEN dari Form Lamaran (2716 pelamar) ═══
-- Semua masuk di tahap 'Applied' — HR update tahap via aplikasi
;